import React from 'react';
import { AsyncStorage } from 'react-native';

const DebuggingModule = () => {
  const [logs, setLogs] = useState([]);

  // Handle network requests
  fetch('https://example.com', {
    method: 'GET',
    headers: {
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ message: 'Hello, world!' })
  })
    .then(response => response.json())
    .catch(error => console.error(error))
    .finally(() => {
      const log = {
        type: 'network request',
        timestamp: Date.now(),
        method: 'GET',
        url: 'https://example.com',
        data: JSON.stringify({ message: 'Hello, world!' })
      };
      setLogs((prevLogs) => [...prevLogs, log]);
    });

  // Handle AsyncStorage operations
  useEffect(() => {
    AsyncStorage.getItem('token')
      .then((token) => console.log('Got token:', token))
      .catch((error) => console.error(error));

    const log = {
      type: 'AsyncStorage operation',
      timestamp: Date.now(),
      action: 'getItem',
      key: 'token'
    };
    setLogs((prevLogs) => [...prevLogs, log]);
  }, []);

  // Handle user actions
  const handleUserAction = (actionType) => {
    console.log('Received user action:', actionType);
    const log = {
      type: 'user action',
      timestamp: Date.now(),
      action: actionType,
    };
    setLogs((prevLogs) => [...prevLogs, log]);
  }

  // Handle state changes
  useEffect(() => {
    const log = {
      type: 'state change',
      timestamp: Date.now(),
      state: JSON.stringify(props.state),
    };
    setLogs((prevLogs) => [...prevLogs, log]);
  }, [props.state]);

  // Handle API responses
  const handleApiResponse = (response) => {
    console.log('Received API response:', response);
    const log = {
      type: 'API response',
      timestamp: Date.now(),
      status: response.status,
      headers: JSON.stringify(response.headers),
      body: response.body,
    };
    setLogs((prevLogs) => [...prevLogs, log]);
  }

  return (
    <View>
      <Text>{logs.length} logs captured</Text>
      <Button title="Clear logs" onPress={() => setLogs([])} />
    </View>
  );
};